const fs = require('fs') as typeof import('fs');
const line: string = fs.readFileSync(0, 'utf8').trim().split('\n')[0];
const [numsStr, targetStr] = line.split('|');
const nums: number[] = numsStr.split(',').map((v) => parseInt(v, 10));
const target: number = parseInt(targetStr, 10);
const seen = new Map<number, number>();
for (let i = 0; i < nums.length; i++) {
  const need = target - nums[i];
  if (seen.has(need)) { console.log(`${seen.get(need)},${i}`); break; }
  seen.set(nums[i], i);
}
